// Trimmed from the CCGL9074 engine's geo.js: the choropleth basemap and the
// bubble layer, the two map modes used here. Topojson now comes from npm.
import { d3, topojson } from './deps.js';
import { createSVG, dur, showTip, hideTip, globalReveal } from './utils.js';
import { useJSON } from './geoWarm.js';

const fmtDefault = (v) => {
  if (v == null || isNaN(v)) return '';
  const abs = Math.abs(v);
  if (abs >= 1e3) return (v / 1e3).toFixed(1) + 'k';
  if (abs >= 1) return Number(v).toFixed(0);
  if (v === 0) return '0';
  return v.toFixed(2);
};

export async function build(sel, props = {}){
  const W = props.width ?? 1200, H = props.height ?? 720;
  const svg = createSVG(sel, W, H);
  const defs = svg.append('defs');
  const root = svg.append('g'); // faded in globally

  const projection = (typeof props.projection === 'function')
    ? props.projection(W, H)
    : d3.geoAlbersUsa().fitSize([W, H], { type: 'Sphere' });
  const path = d3.geoPath(projection);

  const bm = props.basemap || {};
  const mapUrl = bm.url || 'https://cdn.jsdelivr.net/npm/us-atlas@3/states-10m.json';
  const topo = await useJSON(mapUrl);
  const objKey = bm.object || 'states';
  const geo = topojson.feature(topo, topo.objects[objKey]);

  root.append('path').datum({ type: 'Sphere' }).attr('d', path).attr('fill', bm.sphereFill ?? 'rgba(255,255,255,0)');
  const states = root.selectAll('path.state').data(geo.features).join('path')
    .attr('class', 'state')
    .attr('d', path)
    .attr('fill', bm.stateFill ?? 'rgba(255,255,255,.35)')
    .attr('stroke', bm.stateStroke ?? 'rgba(255,255,255,.12)')
    .attr('stroke-width', bm.stateStrokeWidth ?? 0.6);

  let choroplethLegend = null;
  if (bm.choropleth){
    const vMap = bm.choropleth.valueByName || {};
    const val = (typeof vMap === 'function') ? vMap : (name) => vMap[name] ?? 0;
    const range = (bm.choropleth.color && bm.choropleth.color.range) || ['#1f2a44', '#ef5d60'];
    const dom = (bm.choropleth.color && bm.choropleth.color.domain) || [0, 1];
    const color = d3.scaleLinear().domain(dom).range(range);
    choroplethLegend = { scale: color, domain: dom, title: bm.choropleth.legend?.title };
    states.attr('fill', color(0));
    root.node().__animateChoropleth = () => states.transition().duration(dur(900)).attr('fill', d => color(val(d.properties.name)));
  }

  const layers = props.layers || {};
  if (layers.bubbles && Array.isArray(layers.bubbles.data)){
    const Lr = layers.bubbles;
    const lonK = Lr.lon || 'lon', latK = Lr.lat || 'lat', rK = Lr.r || 'value';
    const r = d3.scaleSqrt().domain([0, d3.max(Lr.data, d => +d[rK])]).range(Lr.rRange || [6, 36]);
    const nodes = root.append('g').attr('class', 'bubbles').selectAll('g.m').data(Lr.data).join('g').attr('class', 'm')
      .attr('transform', d => { const p = projection([+d[lonK], +d[latK]]); return p ? `translate(${p})` : null; });
    const r0 = d => Math.max(3, r(d[rK]) * 0.25);
    const circles = nodes.append('circle').attr('r', d => r0(d))
      .attr('fill', Lr.style?.fill ?? 'rgba(247,178,103,.25)')
      .attr('stroke', Lr.style?.stroke ?? 'rgba(247,157,101,1)')
      .attr('stroke-width', Lr.style?.strokeWidth ?? 1.6);
    let labels = null;
    if (Lr.label?.show !== false){
      labels = nodes.append('text')
        .attr('y', d => -r0(d) - 6)
        .attr('text-anchor', Lr.label?.anchor ?? 'middle')
        .attr('fill', Lr.label?.color ?? 'var(--ink)')
        .attr('font-weight', Lr.label?.weight ?? 600)
        .attr('font-size', Lr.label?.fontSize ?? '14px')
        .text(d => Lr.label?.text ? Lr.label.text(d) : `${d.name}`);
    }
    root.node().__animateBubbles = () => {
      circles.transition().duration(dur(Lr.anim?.growMs ?? 1400)).ease(d3.easeCubicOut).attr('r', d => r(d[rK]));
      if (labels) labels.transition().duration(dur(1200)).ease(d3.easeCubicOut).attr('y', d => -r(d[rK]) - 6);
    };
    if (Lr.tooltip !== false){
      const ptsB = Lr.data;
      svg.on('mousemove', (ev) => {
        const [mx, my] = d3.pointer(ev);
        const hit = d3.least(ptsB, d => { const p = projection([+d[lonK], +d[latK]]); if (!p) return 1e9; return Math.hypot(p[0] - mx, p[1] - my) - r(d[rK]); });
        if (!hit) { hideTip(); return; }
        const p = projection([+hit[lonK], +hit[latK]]);
        const dist = p ? Math.hypot(p[0] - mx, p[1] - my) : 1e9;
        if (dist < r(hit[rK]) + 10){
          const html = typeof Lr.tooltip === 'function' ? Lr.tooltip(hit) : `<strong>${hit.name}</strong><br/>${hit[rK]}`;
          showTip(ev.pageX, ev.pageY, html);
        } else hideTip();
      }).on('mouseleave', hideTip);
    }
  }

  // Choropleth gradient legend
  if (choroplethLegend){
    const { scale, domain, title } = choroplethLegend;
    const gradId = `grad-${Math.random().toString(36).slice(2, 7)}`;
    const grad = defs.append('linearGradient').attr('id', gradId).attr('x1', '0%').attr('x2', '100%');
    const steps = 6, d0 = domain[0], d1 = domain[domain.length - 1];
    for (let i = 0; i <= steps; i++){ const t = i / steps; grad.append('stop').attr('offset', `${t * 100}%`).attr('stop-color', scale(d0 + (d1 - d0) * t)); }
    const legendG = svg.append('g').attr('class', 'geo-legend');
    const lw = 220, lh = 12, baseX = 24, baseY = H - 50;
    legendG.append('rect').attr('x', baseX).attr('y', baseY).attr('width', lw).attr('height', lh).attr('fill', `url(#${gradId})`);
    const axisScale = d3.scaleLinear().domain([d0, d1]).range([baseX, baseX + lw]);
    const axisG = legendG.append('g').attr('transform', `translate(0,${baseY + lh})`).call(d3.axisBottom(axisScale).ticks(4).tickSize(0).tickFormat(fmtDefault));
    axisG.selectAll('text').attr('fill', 'var(--muted)').attr('font-size', '11px');
    axisG.selectAll('path,line').remove();
    legendG.append('text').attr('x', baseX).attr('y', baseY - 6).attr('fill', 'var(--muted)').attr('font-size', '12px').text(title || 'Value');
  }

  globalReveal({
    container: sel,
    fadeSel: root,
    ease: d3.easeCubicOut,
    fadeMs: dur(props.anim?.fadeMs ?? 700),
    animateFinal(){
      const R = root.node();
      ['__animateChoropleth', '__animateBubbles'].forEach(fn => { if (typeof R[fn] === 'function'){ try { R[fn](); } catch { /* no-op */ } } });
    }
  });
}
